let cryptoAPI;

if (window.crypto) {
  cryptoAPI = window.crypto;
} else if (window.msCrypto) {
  cryptoAPI = window.msCrypto;
} else {
  throw new Error("Your browser doesn't support the crypto API. Encryption is not possible.");
}

async function ec(text, password) {
    const pwUtf8 = new TextEncoder().encode(password);
    const pwHash = await crypto.subtle.digest('SHA-256', pwUtf8);

    const iv = crypto.getRandomValues(new Uint8Array(12));
    const alg = { name: 'AES-GCM', iv: iv };

    const key = await crypto.subtle.importKey('raw', pwHash, alg, false, ['encrypt']);
    const ptUint8 = new TextEncoder().encode(text);
    const ctBuffer = await crypto.subtle.encrypt(alg, key, ptUint8);

    const ctArray = Array.from(new Uint8Array(ctBuffer));
    const ctStr = ctArray.map(byte => String.fromCharCode(byte)).join('');
    const ctBase64 = btoa(ctStr);

    return {
        c: ctBase64,
        i: Array.from(iv).map(b => b.toString(16).padStart(2, '0')).join('')
    };
}

async function dc(encrypted, password, iv) {
    const pwUtf8 = new TextEncoder().encode(password);                              // encode password as UTF-8
    const pwHash = await crypto.subtle.digest('SHA-256', pwUtf8);                 // hash the password
    const alg = { name: 'AES-GCM', iv: new Uint8Array(iv.match(/.{2}/g).map(byte => parseInt(byte, 16))) };                       // specify algorithm to use, and convert iv to Uint8Array
    const key = await crypto.subtle.importKey('raw', pwHash, alg, false, ['decrypt']); // import key using password hash
  
    // decode encrypted data from base64 to string, and split it into an array of characters
    const encryptedArray = atob(encrypted).split('').map(char => char.charCodeAt(0));
    // convert the array of characters to an ArrayBuffer
    const ctUint8 = new Uint8Array(encryptedArray).buffer;
  
    // decrypt the data
    const ptBuffer = await crypto.subtle.decrypt(alg, key, ctUint8);
  
    // convert the decrypted data from an ArrayBuffer to a string
    const ptString = new TextDecoder().decode(ptBuffer);
  
    // parse the decrypted string as JSON and return the resulting object
    return ptString;
}














































var config;

function arrayBufferToString(array) {
    const view = new Uint8Array(array);
    const chunkSize = 0x8000; // 32k
    let index = 0;
    let result = '';
    while (index < view.byteLength) {
        const chunk = view.slice(index, index + chunkSize);
        result += String.fromCharCode.apply(null, chunk);
        index += chunkSize;
    }
    return result;
}


/**
 * @param {String} url 
 * @returns {NoReturn}
 */
const __init__ = (url) => {
    // self.M.addM('/Local/Libraries/gateway/Js/', 'message.js', 'script');

    var protocol = window.location.protocol === 'http:' ? 'ws://' : 'wss://';
    var url = protocol + url;
    self.config = {
        url: url,
        modules: new Map(),
        onstatechange: undefined
    };
}

/**
 * 
 * @param {String} event
 * @param {Number} token
 * @returns {promise<Json>}
 */
async function messagedata(event, token = undefined) {
    var message = event;
    var data = undefined;

    if (token) {
        var [text, iv] = message.split(':');

        try {
            var result = await decrypt(text, token, iv);
        } catch {
            var result = message;
        }
    } else {
        var result = message;
    }

    try {
        var data = JSON.parse(result);
    } catch {
        
    }

    if (!data) {
        console.log('Les données reçus sont illisibles');
        return {};
    }

    return data;
}


/**
 * @param {MessageEvent} event 
 */
const onmessage = async (event) => {
    var message = event.data;

    if (self.config.id) {
        var [text, iv] = message.split(':');
        try {
            var result = await decrypt(text, self.config.id, iv);
        } catch {
            var result = message;
        }
    } else {
        var result = message;
    }

    var data = await messagedata(result, self.me.Token)

    if (data.id) {
        self.config.id = data.id;
        send_json({
            User: {
                token: self.me.Token
            }
        }, false);
    }

    if (data == {}) {
        return;
    }

    if (data.event) {
        var _func = self.config.modules.get(data.event);
        if (_func) {
            _func(data);
        }
    }
}

/**
 * @param {String} value
 * @param {Bool} crypt
 * @returns {Bool}
 */
const wss_send = async (value, crypt = true) => {
    if (this.config.state != 'open') {
        return false;
    }

    if (crypt) {
        var data = await encrypt(value, self.me.Token);
        var value = `${data.ciphertext}:${data.iv}`;
    }
    
    if (self.config.id) {
        var data = await encrypt(value, self.config.id);
        var value = `${data.ciphertext}:${data.iv}`;
    } else {
        return;
    }

    let hex = '';
    for (let i = 0; i < value.length; i++) {
        hex += value.charCodeAt(i).toString(16);
    }

    var deflater = new Zlib.Deflate(new Uint8Array(btoa(hex).split('').map(function(x){return x.charCodeAt(0)})));
    var compressed = deflater.compress();
    
    // Convertir les données compressées en chaîne de caractères
    var compressedStr = "";
    for (var i = 0; i < compressed.length; i++) {
      compressedStr += String.fromCharCode(compressed[i]);
    }
    
    try {
        self.config.wss.send(stringToArrayBuffer(compressedStr));
        return true;
    } catch (e) {
        console.log(e);
        return false;
    }

}

/**
 * @param {Json} value 
 * @param {Bool} crypt
 * @returns {Bool}
 */
const send_json = (value, crypt = true) => {
    return wss_send(JSON.stringify(value), crypt);
}


/**
 * @returns {NoReturn}
 */
const start = () => {
    self.config.wss = new WebSocket(self.config.url);

    self.config.binaryType="arraybuffer"

    self.config.wss.binaryType = 'arraybuffer'; // définition du type de données binaires à envoyer

    /**
     * @param {CloseEvent} event 
     */
    self.config.wss.onclose = (event) => {
        self.config.state = 'close';
        if (self.config.onstatechange) {
            self.config.onstatechange(event)
        }
        self.config.backstate = 'close';
    }
    /**
     * @param {Event} event 
     */
    self.config.wss.onerror = (event) => {
        self.config.state = 'error';
        if (self.config.onstatechange) {
            self.config.onstatechange(event)
        }
        self.config.backstate = 'error';
    }

    self.config.wss.onmessage = onmessage

    /**
     * @param {Event} event 
     */
    self.config.wss.onopen = (event) => {
        self.config.state = 'open';
        if (self.config.onstatechange) {
            self.config.onstatechange(event)
        }
        self.config.backstate = 'open';
        setInterval(() => {
            if (self.config.state == 'open') {
                send_json({
                    event: 'ping',
                    time: new Date().getTime()
                })
            }
        }, 1000);
    }

}

