class Gateway {
    constructor(u){
        const p = (window.location.protocol === 'http:' ? 'ws://' : 'wss://') + u;
        this.c = {
            p:p,
            m:{},
            osc:false,
            s: 'pending'
        }
    }
    async sd(v,c=true){
        if(this.c.s!='open'||!self.me.T||!this.c.i){
            return;
        }

        if(c){
            var d=await ec(v, self.me.T);
            var v=`${d.c}:${d.i}`;
        }

        var d=await ec(v,this.c.i);
        var v=`${d.c}:${d.i}`;

        var d=new Z.D(new Uint8Array(btoa(v).split('').map(function(x){return x.charCodeAt(0)}))).c();

        try {
            this.c.w.send(d);
        } catch (err) {
            console.log(err);
        }
    }
    o(e){
        if(this.c.osc){this.c.osc('open');}
        this.c.s = 'open';
    }
    l(e){
        if(this.c.osc){this.c.osc('close');}
        this.c.s = 'close';
    }
    async m(e){
        var m = e.data;

        try {
            var a = new Uint8Array(await m.arrayBuffer());
            var g = new Z.I(a).d();
            var m = "";
            for (var i = 0; i < g.length; i++) {
                m += String.fromCharCode(g[i]);
            }
            var m = atob(m);
        } catch (err) {
            console.log('Une erreur est survenue', err);
            return;
        }
        var r=null;
        
        if (this.c.i) {
            try{
                var [c,i]=m.split(':');
                var r = await dc(c,this.c.i,i);
            } catch {}
        }

        if (!r) {
            var r = m;
        }

        if(self.me.T){
            try{
                var [c,i]=r.split(':');
                var r = await dc(c,self.me.T,i);
            } catch {}
        }

        try {
            var d = JSON.parse(r);
        } catch {
            console.log('Les données reçus sont ilisible');
            return;
        }

        if (d.id){
            this.c.i = d.id;
            sj({"User": {"token": self.me.T}}, false);
        }
    }
    e(e){
        if(this.c.osc){this.c.osc('error');}
        this.c.s = 'error';
    }
    s(){
        this.c.s = 'pending';

        this.c.w=new WebSocket(this.c.p);
        this.c.w.onclose    = (e)=>{this.l(e)};
        this.c.w.onerror    = (e)=>{this.e(e)};
        this.c.w.onopen     = (e)=>{this.o(e)};
        this.c.w.onmessage  = (e)=>{this.m(e)};
    }
}
const sj = (m,c=true) => {
    if (self.G){
        self.G.sd(JSON.stringify(m),c);
    }
}

